link.script:
  // 🟢 KONFIGURASI APLIKASI
  const AUTH_SCRIPT_URL = 'https://script.google.com/macros/s/AKfycbyYn-DVnvWkTyjK0VgmuVvVSVODnzRUT6s_hwx_ymMDi9bTMCMs7CpcVrbuh071BXpopA/exec';
  const HALAMAN_MITRA_URL = 'merchant.html'; 
  
  const isDriverRegistrationOpen = false; 
  const adminWhatsAppNumber = "6285601232027"; 

  let currentMode = 'login';

  document.addEventListener("DOMContentLoaded", function() { cekSesiUser(); });

  // FUNGSI FORMAT NOMOR WA (Standarisasi ke 62...)
  function formatWA(number) {
      let formatted = number.toString().replace(/\D/g, ''); // Hapus karakter non-angka
      if (formatted.startsWith('0')) {
          formatted = '62' + formatted.substring(1);
      } else if (formatted.startsWith('8')) {
          formatted = '62' + formatted;
      }
      return formatted;
  }

  // FUNGSI ENKRIPSI PASSWORD (Sama dengan Halaman Mitra)
  async function hashPassword(password) {
      if (!password) return "";
      const msgBuffer = new TextEncoder().encode(password);
      const hashBuffer = await crypto.subtle.digest('SHA-256', msgBuffer);
      const hashArray = Array.from(new Uint8Array(hashBuffer));
      const hashHex = hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
      return hashHex;
  }

  function handleRoleChange() {
      if (currentMode !== 'register') return;

      const selectedRole = document.querySelector('input[name="role"]:checked').value;
      const wrapperNama = document.getElementById('wrapperNamaLengkap');
      const wrapperWaPass = document.getElementById('wrapperWaPass');
      const btnSubmit = document.getElementById('btnSubmitAuth');
      const closedMsg = document.getElementById('driverClosedMessage');

      document.getElementById('authMessage').classList.add('hidden');

      if (selectedRole === 'Driver' && !isDriverRegistrationOpen) {
          wrapperNama.classList.add('hidden'); wrapperWaPass.classList.add('hidden');
          btnSubmit.classList.add('hidden'); closedMsg.classList.remove('hidden');
      } else {
          wrapperNama.classList.remove('hidden'); wrapperWaPass.classList.remove('hidden');
          btnSubmit.classList.remove('hidden'); closedMsg.classList.add('hidden');
      }
  }

  function cekSesiUser() {
      const sesiString = localStorage.getItem('anturun_session');
      if (sesiString) {
          const user = JSON.parse(sesiString);
          if (user && user.userId) {
              window.location.href = HALAMAN_MITRA_URL;
          } else {
              localStorage.removeItem('anturun_session');
          }
      }
  }

  function switchTab(mode) {
      currentMode = mode;
      const tabLogin = document.getElementById('tabLogin'), tabRegister = document.getElementById('tabRegister');
      const regFields = document.getElementById('registerFields');
      const btnForgot = document.getElementById('btnForgotPass');
      
      document.getElementById('authMessage').classList.add('hidden');
      
      if (mode === 'login') {
          tabLogin.className = "flex-1 py-2.5 font-bold text-[13px] rounded-lg bg-white shadow text-[#EE4D2D] transition-all duration-200 outline-none";
          tabRegister.className = "flex-1 py-2.5 font-bold text-[13px] rounded-lg text-gray-500 hover:text-gray-700 transition-all duration-200 outline-none";
          regFields.classList.add('hidden'); 
          btnForgot.classList.remove('hidden');
          document.getElementById('btnSubmitAuth').innerText = "Masuk Sekarang";
      } else {
          tabRegister.className = "flex-1 py-2.5 font-bold text-[13px] rounded-lg bg-white shadow text-[#EE4D2D] transition-all duration-200 outline-none";
          tabLogin.className = "flex-1 py-2.5 font-bold text-[13px] rounded-lg text-gray-500 hover:text-gray-700 transition-all duration-200 outline-none";
          regFields.classList.remove('hidden'); 
          btnForgot.classList.add('hidden');
          document.getElementById('btnSubmitAuth').innerText = "Daftar Akun Mitra"; 
          handleRoleChange();
      }
  }

  function showMessage(text, type, targetElId = 'authMessage') {
      const msgEl = document.getElementById(targetElId);
      msgEl.innerHTML = text;
      msgEl.classList.remove('hidden', 'bg-red-50', 'text-red-600', 'border-red-200', 'bg-green-50', 'text-green-700', 'border-green-200');
      if (type === 'error') {
          msgEl.classList.add('bg-red-50', 'text-red-600', 'border-red-200'); 
      } else {
          msgEl.classList.add('bg-green-50', 'text-green-700', 'border-green-200');
      }
  }

  // LOGIKA RESET KATA SANDI
  function showResetForm() {
      document.getElementById('panelAuth').classList.add('hidden');
      document.getElementById('panelReset').classList.remove('hidden');
      document.getElementById('resetMessage').classList.add('hidden');
      document.getElementById('formReset').reset();
  }

  function hideResetForm() {
      document.getElementById('panelReset').classList.add('hidden');
      document.getElementById('panelAuth').classList.remove('hidden');
  }

  function showResetMessage(text, type) {
      const msgEl = document.getElementById('resetMessage');
      msgEl.innerHTML = text;
      msgEl.classList.remove('hidden', 'bg-red-50', 'text-red-600', 'border-red-200', 'bg-green-50', 'text-green-700', 'border-green-200');
      if (type === 'error') {
          msgEl.classList.add('bg-red-50', 'text-red-600', 'border-red-200');
      } else {
          msgEl.classList.add('bg-green-50', 'text-green-700', 'border-green-200');
      }
  }

  // LOGIKA PERMINTAAN KODE OTP (MANUAL)
  function requestOTP() {
      const rawWa = document.getElementById('inpResetWa').value.trim();
      const wa = formatWA(rawWa);

      if (!wa || wa.length < 9) {
          showResetMessage("Masukkan Nomor WhatsApp yang valid terlebih dahulu!", "error");
          return;
      }

      document.getElementById('resetMessage').classList.add('hidden');
      document.getElementById('authLoading').classList.replace('hidden', 'flex');
      document.getElementById('loadingText').innerText = "Membuat OTP...";

      const payload = { action: 'request_reset_otp', wa: wa };

      fetch(AUTH_SCRIPT_URL, {
          method: 'POST',
          redirect: 'follow',
          headers: { 'Content-Type': 'text/plain;charset=utf-8' },
          body: JSON.stringify(payload)
      })
      .then(async res => {
          const text = await res.text();
          try { return JSON.parse(text); } catch(err) { throw new Error("Respon Server Tidak Valid."); }
      })
      .then(data => {
          document.getElementById('authLoading').classList.replace('flex', 'hidden');
          document.getElementById('loadingText').innerText = "Memproses Data..."; 
          
          if (data.status === 'success') {
              // Tampilkan pesan dengan tautan langsung ke WA Admin
              const pesanWa = encodeURIComponent(`Halo Admin, saya ingin melakukan reset kata sandi akun Anturun. Mohon berikan kode OTP untuk nomor WA saya: ${wa}`);
              const waLink = `https://wa.me/${adminWhatsAppNumber}?text=${pesanWa}`;
              showResetMessage(`OTP berhasil dibuat sistem! 
👉 Hubungi Admin untuk Meminta Kode`, "success");
              
              // Hitung mundur agar tombol tidak bisa di-spam
              const btnOtp = document.getElementById('btnMintaOtp');
              btnOtp.disabled = true;
              btnOtp.classList.add('opacity-50', 'cursor-not-allowed');
              let timeLeft = 60;
              const timer = setInterval(() => {
                  btnOtp.innerText = `${timeLeft}s`;
                  timeLeft--;
                  if (timeLeft < 0) {
                      clearInterval(timer);
                      btnOtp.disabled = false;
                      btnOtp.classList.remove('opacity-50', 'cursor-not-allowed');
                      btnOtp.innerText = "Minta OTP";
                  }
              }, 1000);
          } else {
              showResetMessage(data.message || "Gagal membuat OTP.", "error");
          }
      })
      .catch(err => {
          document.getElementById('authLoading').classList.replace('flex', 'hidden');
          document.getElementById('loadingText').innerText = "Memproses Data...";
          showResetMessage("Terjadi kesalahan saat meminta OTP.", "error");
      });
  }

  document.getElementById('formReset').addEventListener('submit', async function(e) {
      e.preventDefault();
      document.getElementById('resetMessage').classList.add('hidden');

      const rawWa = document.getElementById('inpResetWa').value.trim();
      const otp = document.getElementById('inpResetOtp').value.trim();
      const pass = document.getElementById('inpResetPass').value.trim();
      const passConfirm = document.getElementById('inpResetPassConfirm').value.trim();

      // Standarisasi nomor WA
      const wa = formatWA(rawWa);

      if (!wa || wa.length < 9) {
          showResetMessage("Nomor WhatsApp tidak valid!", "error");
          return;
      }

      // Validasi OTP
      if (!/^\d{6}$/.test(otp)) {
          showResetMessage("Kode OTP harus berupa 6 digit angka!", "error");
          return;
      }

      if (pass !== passConfirm) {
          showResetMessage("Kata sandi baru dan konfirmasi tidak cocok!", "error");
          return;
      }

      document.getElementById('authLoading').classList.replace('hidden', 'flex');
      
      // Hash kata sandi baru
      const hashedPassword = await hashPassword(pass);

      const payload = {
          action: 'reset_password',
          wa: wa,
          otp: otp, // Kirim OTP ke backend untuk dicocokkan
          newPassword: hashedPassword
      };

      fetch(AUTH_SCRIPT_URL, {
          method: 'POST',
          redirect: 'follow',
          headers: { 'Content-Type': 'text/plain;charset=utf-8' },
          body: JSON.stringify(payload)
      })
      .then(async res => {
          const text = await res.text();
          try { return JSON.parse(text); } catch(err) { throw new Error("Respon Server Tidak Valid."); }
      })
      .then(data => {
          document.getElementById('authLoading').classList.replace('flex', 'hidden');
          if (data.status === 'success') {
              hideResetForm();
              showMessage("Kata sandi berhasil direset! Silakan masuk dengan sandi baru Anda.", "success");
          } else {
              showResetMessage(data.message || "Gagal mereset kata sandi. Nomor WhatsApp tidak ditemukan.", "error");
          }
      })
      .catch(err => {
          document.getElementById('authLoading').classList.replace('flex', 'hidden');
          showResetMessage("Terjadi kesalahan koneksi atau server sibuk.", "error");
      });
  });

  // LOGIKA LOGIN & REGISTER
  document.getElementById('formAuth').addEventListener('submit', async function(e) {
      e.preventDefault();
      document.getElementById('authMessage').classList.add('hidden'); 
      document.getElementById('authLoading').classList.replace('hidden', 'flex');
      
      const rawWa = document.getElementById('inpWa').value.toString().trim();
      const waFormatted = formatWA(rawWa); // Standarisasi Nomor WA

      if (!waFormatted || waFormatted.length < 9) {
          document.getElementById('authLoading').classList.replace('flex', 'hidden');
          showMessage("Nomor WhatsApp tidak valid!", "error");
          return;
      }

      // Ambil Password Asli dan Hash
      const rawPassword = document.getElementById('inpPass').value.toString().trim();
      const hashedPassword = await hashPassword(rawPassword);

      const payload = { 
        action: currentMode === 'login' ? 'login' : 'register_user', 
        wa: waFormatted, 
        password: hashedPassword // Gunakan Password yang sudah di-hash
      };
      
      if (currentMode === 'register') { 
        payload.nama = document.getElementById('inpNama').value.trim(); 
        payload.role = document.querySelector('input[name="role"]:checked').value; 
      }

      fetch(AUTH_SCRIPT_URL, { 
        method: 'POST', 
        redirect: 'follow', 
        headers: { 'Content-Type': 'text/plain;charset=utf-8' }, 
        body: JSON.stringify(payload) 
      })
      .then(async res => { 
        const text = await res.text(); 
        try { return JSON.parse(text); } catch(err) { throw new Error("Respon Server Tidak Valid."); } 
      })
      .then(data => {
          document.getElementById('authLoading').classList.replace('flex', 'hidden');
          if (data.status === 'success') {
              if (data.statusAkun === 'Pending') {
                  const pesanWa = encodeURIComponent(`Halo Admin, saya baru saja mendaftar sebagai Driver Anturun dengan nomor WA ${waFormatted} dan ingin meminta verifikasi akun.`);
                  const waLink = `https://wa.me/${adminWhatsAppNumber}?text=${pesanWa}`;
                  showMessage(`Pendaftaran Berhasil! Hubungi Admin Disini`, "success");
              }
              else { 
                  localStorage.setItem('anturun_session', JSON.stringify(data.user)); 
                  window.location.href = HALAMAN_MITRA_URL;
              }
          } else {
              showMessage(data.message, "error");
          }
      }).catch(err => { 
        document.getElementById('authLoading').classList.replace('flex', 'hidden'); 
        showMessage("Terjadi kesalahan koneksi atau server sibuk.", "error"); 
      });
  });
